import{_ as a,o as t,c as r,ag as o}from"./chunks/framework.DAAaZ98D.js";const d=JSON.parse('{"title":"","description":"","frontmatter":{"layout":"home","hero":{"name":"飞跃手册","actions":[{"theme":"brand","text":"最近更新","link":"updates"},{"theme":"brand","text":"分享经验","link":"docs/contribute"}]},"type":"page"},"headers":[],"relativePath":"index.md","filePath":"index.md"}'),i={name:"index.md"};function n(s,e,l,h,c,p){return t(),r("div",null,[...e[0]||(e[0]=[o('<h2 id="飞跃手册是什么" tabindex="-1">飞跃手册是什么？ <a class="header-anchor" href="#飞跃手册是什么" aria-label="Permalink to &quot;飞跃手册是什么？&quot;">​</a></h2><p>本平台是一个港中深学生自发搭建的<em>申请经验/找工实习/人生规划</em>信息共享平台。我们欢迎所有港中深毕业生在此分享自己的经验，以帮助学弟学妹们在相同的路上少走弯路。我们希望这个平台能够被持续维护下去，并促进构建一个强大的校友网络。关于飞跃手册的更多介绍，请参考<a href="https://sustech-application.com/" target="_blank" rel="noreferrer">南方科技大学飞跃手册</a>。</p><p>在此，我们还想为所有无私分享的同学提供几点在分享信息时的思考角度，希望能够抛砖引玉：</p><ul><li><strong>你的独特性。</strong> 网上已有数百篇申研/找工经验贴，你与它们不同的地方在哪里？例如，哪个举动现在看来是你成功/失败的关键，而网上鲜有人讨论？作为港中深学生，你有什么优势，又遇到了哪些挑战？你能提供哪些有价值的情报（例如，某个学校/公司的面试习惯，或某个小众但高质量的交换项目）？</li><li><strong>换位思考。</strong> 回过头来看，你觉得一两年前的自己最应该知道什么？如果你能对过去的自己说话，时间有限——甚至只有一句话——你会说什么？</li><li><strong>不以结果论英雄。</strong> 我们欢迎所有经历过申请/找工或探索过独特人生道路的同学分享。你之所以能够分享，并不是因为你在某种意义上获得了成功，而是因为你从这个过程中总结出了有益于后人的经验。</li></ul><h3 id="如何分享经验" tabindex="-1">如何分享经验？ <a class="header-anchor" href="#如何分享经验" aria-label="Permalink to &quot;如何分享经验？&quot;">​</a></h3><p>飞跃手册欢迎<strong>所有的毕业生</strong>参考<a href="./docs/contribute">经验分享指南</a>分享你们的故事！</p><h2 id="贡献者" tabindex="-1">贡献者 <a class="header-anchor" href="#贡献者" aria-label="Permalink to &quot;贡献者&quot;">​</a></h2><p>本站的设计、布局和维护方式受到<a href="https://sustech-application.com/" target="_blank" rel="noreferrer">南方科技大学飞跃手册</a>团队的重要影响。本团队也有幸得到了南科大团队的支持，应允直接使用这套开发多年的成熟框架。在此，我们郑重地表示感谢！</p><p>以下是通过GitHub参与投稿的同学：</p><a href="https://github.com/CUHKSZFYSC/cuhkszfysc.github.io/graphs/contributors"><br><img src="https://contributors-img.web.app/image?repo=CUHKSZFYSC/cuhkszfysc.github.io"></a><h2 id="友情链接" tabindex="-1">友情链接 <a class="header-anchor" href="#友情链接" aria-label="Permalink to &quot;友情链接&quot;">​</a></h2><ul><li><a href="https://sustech-application.com/" target="_blank" rel="noreferrer">南方科技大学飞跃手册</a></li><li><a href="http://www.isee.zju.edu.cn/2025/0314/c56480a3027185/page.htm" target="_blank" rel="noreferrer">浙江大学飞跃手册</a></li><li><a href="https://survivesjtu.gitbook.io/survivesjtumanual" target="_blank" rel="noreferrer">上海交大生存手册</a></li></ul><h2 id="意见-改进" tabindex="-1">意见/改进 <a class="header-anchor" href="#意见-改进" aria-label="Permalink to &quot;意见/改进&quot;">​</a></h2><p>本网站处于测试期。</p>',14)])])}const m=a(i,[["render",n]]);export{d as __pageData,m as default};
